//  BLOCKING — freezes the tab for ~2 seconds
function blockingSum() {
  let total = 0;
  for (let i = 0; i < 1_000_000_000; i++) total += i;
  return total;
}
console.log(blockingSum()); // Call Stack occupied — UI frozen

//  NON-BLOCKING — yields to Event Loop between chunks
function nonBlockingSum(total = 0, i = 0) {
  const end = Math.min(i + 1_000_000, 1_000_000_000);
  while (i < end) { total += i; i++; }
  if (i < 1_000_000_000) {
    setTimeout(() => nonBlockingSum(total, i), 0); // yield
  } else {
    console.log('Total:', total); // UI stays responsive throughout
  }
}
nonBlockingSum();

