//  Never do this on the main thread
// while (true) {} // infinite block — tab permanently frozen

//  Safe infinite polling with async pause
async function pollForData() {
  while (true) {
    const data = await fetch('/api/status').then(r => r.json());
    if (data.ready) break;
    await new Promise(r => setTimeout(r, 1000)); // yields every second
  }
}
